+                                warn!(
+                                    restored = report.success_count(),
+                                    failed = report.failure_count(),
+                                    skipped = report.skipped.len(),
+                                    "Scrollback replay completed with warnings"
+                                );
+                            } else {
+                                info!(
+                                    restored = report.success_count(),
+                                    bytes = report.total_bytes(),
